const body = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const prompt = String(body.prompt ?? body.promptRaw ?? '').trim();
if (!prompt) {
  throw new Error('Missing prompt');
}
const mode = String(body.mode ?? 'text-to-image');
const model = String(body.model ?? 'gpt-5.5').trim() || 'gpt-5.5';
const toolModel = String(body.toolModel ?? 'gpt-image-2').trim() || 'gpt-image-2';
const content = [{ type: 'input_text', text: prompt }];
if (mode === 'image-to-image') {
  const source = body.source && typeof body.source === 'object' ? body.source : {};
  const imageBase64 = String(source.imageBase64 ?? '').trim();
  const imageUrl = String(source.imageUrl ?? '').trim();
  const mimeType = String(source.mimeType ?? 'image/png').trim() || 'image/png';
  if (imageBase64) {
    content.push({
      type: 'input_image',
      image_url: imageBase64.startsWith('data:image/') ? imageBase64 : ('data:' + mimeType + ';base64,' + imageBase64),
    });
  } else if (imageUrl) {
    content.push({
      type: 'input_image',
      image_url: imageUrl,
    });
  } else {
    throw new Error('Image-to-image requires source.imageBase64 or source.imageUrl');
  }
}
const requestPayload = {
  model,
  stream: true,
  input: [
    {
      role: 'user',
      content,
    },
  ],
  tool_choice: {
    type: 'image_generation',
  },
  tools: [
    {
      type: 'image_generation',
      model: toolModel,
    },
  ],
};
return [{
  json: {
    requestPayload,
    requestMeta: {
      requestId: String(body.requestId ?? ''),
      mode,
      model,
      toolModel,
      prompt: prompt.slice(0, 400),
    },
  },
}];

const source = $json;
const raw = typeof source.body === 'string'
  ? source.body
  : typeof source.data === 'string'
    ? source.data
    : typeof source === 'string'
      ? source
      : JSON.stringify(source);

const eventTypes = new Set();
const outputTextChunks = [];
const images = [];
const imageSet = new Set();
let hasOutputItemDone = false;

const toDataUrl = (base64, mimeType = 'image/png') => {
  const normalized = String(base64 || '').replace(/\s+/g, '');
  if (!normalized) return '';
  return normalized.startsWith('data:image/') ? normalized : ('data:' + mimeType + ';base64,' + normalized);
};

const addImage = (base64, mimeType = 'image/png') => {
  const src = toDataUrl(base64, mimeType);
  if (!src || imageSet.has(src)) return;
  imageSet.add(src);
  images.push({ src, mimeType });
};

const walk = (node) => {
  if (!node) return;
  if (typeof node === 'string') {
    const trimmed = node.trim();
    if (!trimmed) return;
    if (trimmed.startsWith('{') || trimmed.startsWith('[')) {
      try {
        walk(JSON.parse(trimmed));
      } catch {
        if (trimmed.length > 32) outputTextChunks.push(trimmed);
      }
      return;
    }
    if (trimmed.length > 32) outputTextChunks.push(trimmed);
    return;
  }
  if (Array.isArray(node)) {
    node.forEach(walk);
    return;
  }
  if (typeof node !== 'object') return;

  const nodeType = typeof node.type === 'string' ? node.type : '';
  const nodeEvent = typeof node.event === 'string' ? node.event : '';
  if (nodeType) eventTypes.add(nodeType);
  if (nodeEvent) eventTypes.add(nodeEvent);
  if (nodeType === 'response.output_item.done' || nodeEvent === 'response.output_item.done') {
    hasOutputItemDone = true;
  }

  const mimeType = typeof node.mime_type === 'string'
    ? node.mime_type
    : typeof node.mimeType === 'string'
      ? node.mimeType
      : (typeof node.output_format === 'string' && node.output_format.toLowerCase() === 'jpeg' ? 'image/jpeg' : 'image/png');

  if (nodeType === 'image_generation_call' && typeof node.result === 'string' && node.result.length > 40) {
    addImage(node.result, mimeType);
  }

  const base64Keys = ['b64_json', 'b64', 'base64', 'image_base64', 'imageBase64', 'result'];
  for (const key of base64Keys) {
    const value = node[key];
    if (typeof value === 'string' && value.length > 40) {
      addImage(value, mimeType);
    }
  }

  if (node.inlineData && typeof node.inlineData === 'object' && typeof node.inlineData.data === 'string') {
    addImage(node.inlineData.data, node.inlineData.mimeType || mimeType);
  }

  for (const value of Object.values(node)) {
    walk(value);
  }
};

const normalized = raw.replace(/\r\n/g, '\n').replace(/\r/g, '\n');
const blocks = normalized.split('\n\n').map((item) => item.trim()).filter(Boolean);
let parsedAnyBlock = false;

for (const block of blocks) {
  const lines = block.split('\n');
  let eventType = '';
  const dataLines = [];
  for (const line of lines) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith(':')) continue;
    if (trimmed.startsWith('event:')) {
      eventType = trimmed.slice(6).trim();
      if (eventType) eventTypes.add(eventType);
      if (eventType === 'response.output_item.done') hasOutputItemDone = true;
      continue;
    }
    if (trimmed.startsWith('data:')) {
      dataLines.push(trimmed.slice(5).trim());
      continue;
    }
  }

  if (dataLines.length > 0) {
    parsedAnyBlock = true;
    const merged = dataLines.join('\n').trim();
    if (merged && merged !== '[DONE]') {
      try {
        const payload = JSON.parse(merged);
        if (eventType && (!payload.type || typeof payload.type !== 'string')) {
          payload.type = eventType;
        }
        walk(payload);
      } catch {
        walk(merged);
      }
    }
  }
}

if (!parsedAnyBlock) {
  try {
    walk(JSON.parse(normalized));
  } catch {
    walk(normalized);
  }
}

const outputText = outputTextChunks.join('\n').slice(0, 6000);
return [{
  json: {
    ok: images.length > 0,
    status: images.length > 0 ? 'completed' : 'no_image',
    imageCount: images.length,
    images,
    outputText,
    eventTypes: Array.from(eventTypes),
    hasOutputItemDone,
    rawPreview: raw.slice(0, 12000),
  },
}];
